// 입력에서 sample-ratio 또는 dry-run 플래그 정규화
const input = $input.first().json || {};
const sampleRatio = (typeof input.sample_ratio === 'number') ? input.sample_ratio : 0.05;
const apply = input.apply === true;
const backup = input.backup !== false; // default true

const cmd = [
          'python3', '/repo/data/pipeline/05_build_combination_rules.py',
  '--sample-ratio', String(sampleRatio),
  '--data-dir', '/tmp/polyvore',
  '--color-path', '/repo/data/color/color_matching_rules.json',
  '--combination-path', '/repo/data/combination/item_combination_rules.json'
];
if (apply) cmd.push('--apply');
if (!backup) cmd.push('--no-backup');

return { json: { sample_ratio: sampleRatio, apply, backup, command: cmd.join(' ') } };

// Execute Command 표준 출력 파싱
exec = require('child_process').execSync; // noop import marker (실제 환경에서 사용 안 함)

const item = $input.first().json;
const raw = typeof item === 'string' ? item : (item.stdout ?? JSON.stringify(item));

let report = {};
try { report = JSON.parse(raw); } catch (e) { report = {}; }

const colorVal = report.color_validation || {};
const comboVal = report.combination_validation || {};
const stats = report.polyvore_stats_summary || {};

const valid = !!(colorVal.valid && comboVal.valid);
const bothPass = (colorVal.valid === true) && (comboVal.valid === true);
const dryRun = report.dry_run === true;

return {
  json: {
    valid,
    color_valid: colorVal.valid === true,
    color_errors: colorVal.errors || [],
    color_rule_count: colorVal.rule_count || 0,
    combo_valid: comboVal.valid === true,
    combo_errors: comboVal.errors || [],
    combo_rule_count: comboVal.rule_count || 0,
    stats,
    dry_run: dryRun,
    mismatch: !valid
  }
};
